def hashcode(n: int) -> str:
    return hashlib.sha256(str(n).encode('utf-8')).hexdigest()

import pprint
@pytest.mark.parametrize("d1, d2, result, testcase", q10_testcases)
def test_q10(d1, d2, result, testcase):
    if testcase == True:
        assert eval(pprint.pformat(merge_key(d1, d2))) == result
    else:
        assert hashcode(eval(pprint.pformat(merge_key(d1, d2)))) == result